const body = $input.first().json.body ?? {};
const lead = {
  name: typeof body.name === 'string' ? body.name.trim() : '',
  email: typeof body.email === 'string' ? body.email.trim() : '',
  company: typeof body.company === 'string' ? body.company.trim() : '',
  role: typeof body.role === 'string' ? body.role.trim() : '',
  message: typeof body.message === 'string' ? body.message.trim() : '',
  source: typeof body.source === 'string' ? body.source.trim() : 'unknown',
};
const errors = [];
if (!lead.name) errors.push('name is required');
if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(lead.email)) errors.push('email must be valid');
if (!lead.message) errors.push('message is required');

return [{
  json: {
    valid: errors.length === 0,
    lead,
    errors,
  },
}];

const lead = $('Validate Lead').first().json.lead;
const content = $input.first().json.choices?.[0]?.message?.content;
if (typeof content !== 'string') throw new Error('Manifest returned no qualification text');

const cleaned = content
  .trim()
  .replace(/^```(?:json)?\s*/i, '')
  .replace(/\s*```$/, '');
let qualification;
try {
  qualification = JSON.parse(cleaned);
} catch {
  throw new Error('The model response was not valid JSON');
}

const score = Number(qualification.score);
if (!Number.isFinite(score)) throw new Error('The qualification score is missing');

return [{
  json: {
    ok: true,
    lead,
    qualification: {
      score: Math.max(0, Math.min(100, Math.round(score))),
      summary: String(qualification.summary ?? ''),
      reason: String(qualification.reason ?? ''),
      recommended_action: String(qualification.recommended_action ?? ''),
    },
  },
}];
